import cardStylesText from './coaching-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { navigate } from '../../../router.js';
import { HealthService } from '../../../services/health.service.js';
import { appTodayString } from '../../../services/app-timezone.service.js';
import { formatRelativeStamp } from '../../../utils/coaching-format.js';
import { createComponentLogger } from '../../../utils/component-logger.js';

const cardStyles = cssStyleSheet(cardStylesText);
const log = createComponentLogger('health/coaching-card');

const template = document.createElement('template');
template.innerHTML = `
    <article class="card" data-testid="coaching-card">
        <div class="card__head">
            <span class="card__icon" aria-hidden="true">☀</span>
            <h3 class="card__title">Coaching</h3>
            <span class="card__stamp" data-testid="coaching-card-stamp" hidden></span>
            <span class="card__chevron" aria-hidden="true">›</span>
        </div>
        <p class="card__preview" data-testid="coaching-card-preview" hidden></p>
        <p class="card__note" data-testid="coaching-card-note" hidden></p>
    </article>
`;

/**
 * Story 173 — dashboard entry point into `/health/coaching`. A read-only
 * teaser of today's coaching note: clamped advice preview + stamp when the
 * note is `done`, a muted one-liner for pending/empty/failed, and a muted
 * fallback when the fetch itself fails (offline). It never renders a raw
 * error — the full note and any failure detail live on the screen — and the
 * whole card is always tappable so the screen is reachable in every state.
 *
 * Deliberately resilient: a fetch failure must NOT take down the dashboard's
 * chart/timeline siblings, so loading is self-contained and swallows errors
 * into the muted state (logged, not surfaced).
 */
export class CoachingCard extends HTMLElement {
    private previewEl: HTMLElement | null = null;
    private stampEl: HTMLElement | null = null;
    private noteEl: HTMLElement | null = null;
    /** Exposed for tests/dashboard to await the in-flight load (mirrors chart/timeline). */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        this.shadowRoot!.adoptedStyleSheets = [cardStyles];
        this.shadowRoot!.appendChild(template.content.cloneNode(true));
        this.previewEl = this.shadowRoot!.querySelector('[data-testid="coaching-card-preview"]');
        this.stampEl = this.shadowRoot!.querySelector('[data-testid="coaching-card-stamp"]');
        this.noteEl = this.shadowRoot!.querySelector('[data-testid="coaching-card-note"]');
    }

    connectedCallback(): void {
        this.addEventListener('click', () => navigate('/health/coaching'));
        this.loadPromise = this.load();
    }

    private showNote(text: string): void {
        if (this.previewEl) this.previewEl.hidden = true;
        if (this.stampEl) this.stampEl.hidden = true;
        if (this.noteEl) {
            this.noteEl.textContent = text;
            this.noteEl.hidden = false;
        }
    }

    private async load(): Promise<void> {
        try {
            const row = await HealthService.fetchCoaching();

            if (!row) {
                this.showNote('No coaching yet — tap to view');
                return;
            }

            if (row.status === 'pending') {
                this.showNote('Coaching is queued for this morning');
                return;
            }

            if (row.status === 'failed') {
                this.showNote('Coaching failed — tap to view');
                return;
            }

            // status === 'done'
            if (this.noteEl) this.noteEl.hidden = true;
            if (this.previewEl) {
                this.previewEl.textContent = row.advice ?? '';
                this.previewEl.hidden = false;
            }
            if (this.stampEl) {
                const stamp = formatRelativeStamp(row.generated_at, appTodayString());
                this.stampEl.textContent = stamp;
                this.stampEl.hidden = stamp === '';
            }
        } catch (err) {
            // Degrade quietly — the dashboard must survive a coaching fetch failure.
            log.error('fetchCoaching failed:', err);
            this.showNote('Coaching unavailable — tap to view');
        }
    }
}

if (!customElements.get('coaching-card')) {
    customElements.define('coaching-card', CoachingCard);
}
