import stylesText from './nutrition-card.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { formatMacro } from '../../../../utils/format-macro.js';
import { HealthService } from '../../../../services/health.service.js';
import { createComponentLogger } from '../../../../utils/component-logger.js';

const styles = cssStyleSheet(stylesText);
import type { ConsumptionEntry } from '@motivation/shared';

const template = document.createElement('template');
template.innerHTML = `
    <div class="nutrition-card" id="nutrition-card" hidden>
        <div class="nc-header">
            <span class="nc-icon">🍽️</span>
            <span class="nc-calories" id="nc-cal">0 kcal</span>
        </div>
        <div class="nc-macros">
            <span class="nc-macro" id="nc-p">P:0g</span>
            <span class="nc-macro" id="nc-c">C:0g</span>
            <span class="nc-macro" id="nc-f">F:0g</span>
            <span class="nc-macro" id="nc-fb">Fb:0g</span>
            <span class="nc-macro" id="nc-sugar">Sugar:0g</span>
            <span class="nc-macro" id="nc-na">Na:0mg</span>
        </div>
    </div>
    <pre class="screen-error" hidden></pre>
`;

export class NutritionCard extends HTMLElement {
    static readonly observedAttributes = ['date'];
    private readonly log = createComponentLogger('nutrition-card');
    private loadSequence = 0;
    /** Resolves when the most recent load() call finishes — exposed for tests and external awaits. */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name === 'date' && newValue) {
            this.load(newValue);
        }
    }

    load(date: string): Promise<void> {
        const currentLoad = ++this.loadSequence;
        this.loadPromise = (async () => {
            try {
                const entries = await HealthService.fetchConsumptionByDate(date);
                if (currentLoad !== this.loadSequence) return;
                this.render(entries);
            } catch (err) {
                if (currentLoad !== this.loadSequence) return;
                this.log.error('Failed to load consumption for', date, err);
                this.setError(err);
            }
        })();
        return this.loadPromise;
    }

    private render(entries: ConsumptionEntry[]): void {
        const shadow = this.shadowRoot!;
        const card = shadow.getElementById('nutrition-card')!;
        shadow.querySelector<HTMLElement>('.screen-error')!.hidden = true;

        if (entries.length === 0) {
            card.hidden = true;
            this.hidden = true;
            return;
        }
        this.hidden = false;

        const totalCal = entries.reduce((sum, e) => sum + (e.calories ?? 0), 0);
        const totalProtein = entries.reduce((sum, e) => sum + (e.protein_g ?? 0), 0);
        const totalCarbs = entries.reduce((sum, e) => sum + (e.carbs_g ?? 0), 0);
        const totalFat = entries.reduce((sum, e) => sum + (e.fat_g ?? 0), 0);
        const totalFiber = entries.reduce((sum, e) => sum + (e.fiber_g ?? 0), 0);
        const totalSugar = entries.reduce((sum, e) => sum + (e.sugar_g ?? 0), 0);
        const totalSodium = entries.reduce((sum, e) => sum + (e.sodium_mg ?? 0), 0);

        shadow.getElementById('nc-cal')!.textContent = `${formatMacro(totalCal)} kcal`;
        shadow.getElementById('nc-p')!.textContent = `P:${formatMacro(totalProtein)}g`;
        shadow.getElementById('nc-c')!.textContent = `C:${formatMacro(totalCarbs)}g`;
        shadow.getElementById('nc-f')!.textContent = `F:${formatMacro(totalFat)}g`;
        shadow.getElementById('nc-fb')!.textContent = `Fb:${formatMacro(totalFiber)}g`;
        shadow.getElementById('nc-sugar')!.textContent = `Sugar:${formatMacro(totalSugar)}g`;
        shadow.getElementById('nc-na')!.textContent = `Na:${formatMacro(totalSodium)}mg`;
        card.hidden = false;
    }

    private setError(err: unknown): void {
        const shadow = this.shadowRoot!;
        this.hidden = false;
        shadow.getElementById('nutrition-card')!.hidden = true;
        const errorEl = shadow.querySelector<HTMLElement>('.screen-error')!;
        errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        errorEl.hidden = false;
    }
}

customElements.define('nutrition-card', NutritionCard);
