import stylesText from './timeline-day.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import '../activity-card/activity-card.component.js';
import '../nutrition-card/nutrition-card.component.js';
import { navigate } from '../../../../router.js';
import { appTodayPlainDate } from '../../../../services/app-timezone.service.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="timeline-day" id="day-container">
        <div class="day-content">
            <div class="date-header">
                <span class="date-label" id="date-label"></span>
                <span class="date-value" id="date-value"></span>
            </div>
            <div class="split-view">
                <div class="left-pane" id="activities-pane">
                    <activity-card></activity-card>
                </div>
                <div class="spine-node"></div>
                <div class="right-pane" id="nutrition-pane">
                    <nutrition-card></nutrition-card>
                </div>
            </div>
        </div>
    </div>
`;

export class TimelineDay extends HTMLElement {
    static readonly observedAttributes = ['date'];

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        shadow.getElementById('day-container')!.addEventListener('click', () => {
            const date = this.getAttribute('date');
            if (date) {
                navigate(`/health/day/${date}`);
            }
        });
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name !== 'date' || !newValue) return;
        const shadow = this.shadowRoot!;

        const { label, value } = this.formatDateHeader(newValue);
        shadow.getElementById('date-label')!.textContent = label;
        shadow.getElementById('date-value')!.textContent = value;

        shadow.querySelector('activity-card')!.setAttribute('date', newValue);
        shadow.querySelector('nutrition-card')!.setAttribute('date', newValue);
    }

    private formatDateHeader(dateStr: string): { label: string; value: string } {
        const d = Temporal.PlainDate.from(dateStr);
        const today = appTodayPlainDate();
        const dateValue = d.toLocaleString(undefined, { day: 'numeric', month: 'short' });

        if (d.equals(today)) {
            return { label: 'Today', value: dateValue };
        }

        const yesterday = today.subtract({ days: 1 });
        if (d.equals(yesterday)) {
            return { label: 'Yesterday', value: dateValue };
        }

        return { label: d.toLocaleString(undefined, { weekday: 'long' }), value: dateValue };
    }
}

customElements.define('timeline-day', TimelineDay);
