import stylesText from './calorie-trend-chart.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { formatMacro } from '../../../utils/format-macro.js';
import { HealthService } from '../../../services/health.service.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { appTodayPlainDate } from '../../../services/app-timezone.service.js';

const styles = cssStyleSheet(stylesText);
import type { DailyNutritionSummary } from '@motivation/shared';

const template = document.createElement('template');
template.innerHTML = `
    <p class="screen-loading" hidden>Loading…</p>
    <pre class="screen-error" hidden></pre>
    <button class="screen-retry" type="button" hidden>Retry</button>
    <div class="trend-container" id="trend-section" hidden>
        <div class="trend-chart" id="trend-chart">
            <div class="target-line" id="target-line" hidden>
                <span class="target-label" id="target-label"></span>
            </div>
            <div class="trend-bars" id="trend-bars"></div>
        </div>
        <div id="empty-state" class="empty-state" hidden>
            No nutrition data yet.
        </div>
    </div>
`;

export class CalorieTrendChart extends HTMLElement {
    private _calorieTarget = 2500;
    private readonly log = createComponentLogger('calorie-trend-chart');
    private loadSequence = 0;
    /** Resolves when the most recent load() call finishes — exposed for tests and external retry awaits. */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        const stored = localStorage.getItem('health_calorie_target');
        if (stored) {
            const parsed = parseInt(stored, 10);
            if (parsed > 0) this._calorieTarget = parsed;
        }

        shadow.querySelector<HTMLButtonElement>('.screen-retry')!
            .addEventListener('click', () => { this.load(); });
    }

    connectedCallback(): void {
        this.load();
    }

    set calorieTarget(value: number) {
        this._calorieTarget = value;
        localStorage.setItem('health_calorie_target', String(value));
    }

    get calorieTarget(): number {
        return this._calorieTarget;
    }

    load(): Promise<void> {
        const currentLoad = ++this.loadSequence;
        this.setLoading();
        this.loadPromise = (async () => {
            try {
                const today = appTodayPlainDate();
                const from = today.subtract({ days: 6 }).toString();
                const to = today.toString();
                const summaries = await HealthService.fetchNutritionSummary(from, to);
                if (currentLoad !== this.loadSequence) return;
                this.render(summaries);
            } catch (err) {
                if (currentLoad !== this.loadSequence) return;
                this.log.error('Failed to load calorie trend', err);
                this.setError(err);
            }
        })();
        return this.loadPromise;
    }

    private setLoading(): void {
        const shadow = this.shadowRoot!;
        shadow.querySelector<HTMLElement>('.screen-loading')!.hidden = false;
        shadow.querySelector<HTMLElement>('.screen-error')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-retry')!.hidden = true;
        shadow.getElementById('trend-section')!.hidden = true;
    }

    private setError(err: unknown): void {
        const shadow = this.shadowRoot!;
        const errorEl = shadow.querySelector<HTMLElement>('.screen-error')!;
        errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        errorEl.hidden = false;
        shadow.querySelector<HTMLElement>('.screen-loading')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-retry')!.hidden = false;
        shadow.getElementById('trend-section')!.hidden = true;
    }

    private render(summaries: DailyNutritionSummary[]): void {
        const shadow = this.shadowRoot!;
        const barsContainer = shadow.getElementById('trend-bars')!;
        barsContainer.replaceChildren();

        const calByDate = new Map(summaries.map(s => [s.date, s.total_calories]));

        const days: { date: string; dayLabel: string; calories: number }[] = [];
        for (let i = 6; i >= 0; i--) {
            const d = appTodayPlainDate().subtract({ days: i });
            const dateStr = d.toString();

            days.push({
                date: dateStr,
                dayLabel: d.toLocaleString(undefined, { weekday: 'short' }),
                calories: calByDate.get(dateStr) ?? 0,
            });
        }

        const peak = Math.max(...days.map(d => d.calories));
        const chartCeiling = Math.max(peak, this._calorieTarget * 1.2, 1);

        const targetLine = shadow.getElementById('target-line')!;
        const targetLabel = shadow.getElementById('target-label')!;
        const targetPercent = (this._calorieTarget / chartCeiling) * 100;
        targetLine.style.bottom = `${targetPercent}%`;
        targetLabel.textContent = formatMacro(this._calorieTarget);
        targetLine.hidden = false;

        for (const day of days) {
            const wrapper = document.createElement('div');
            wrapper.className = 'trend-bar-wrapper';

            const bar = document.createElement('div');
            bar.className = 'trend-bar';
            const heightPercent = (day.calories / chartCeiling) * 100;
            bar.style.height = `${heightPercent}%`;

            if (day.calories > this._calorieTarget) {
                bar.classList.add('over-target');
            }

            const calLabel = document.createElement('div');
            calLabel.className = 'trend-cal';
            calLabel.textContent = day.calories > 0 ? formatMacro(day.calories) : '';

            const dayLabel = document.createElement('div');
            dayLabel.className = 'trend-day';
            dayLabel.textContent = day.dayLabel;

            wrapper.appendChild(calLabel);
            wrapper.appendChild(bar);
            wrapper.appendChild(dayLabel);
            barsContainer.appendChild(wrapper);
        }

        const hasTrendData = summaries.length > 0;
        shadow.getElementById('trend-chart')!.hidden = !hasTrendData;
        shadow.getElementById('empty-state')!.hidden = hasTrendData;
        shadow.getElementById('trend-section')!.hidden = false;
        shadow.querySelector<HTMLElement>('.screen-loading')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-error')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-retry')!.hidden = true;
    }
}

customElements.define('calorie-trend-chart', CalorieTrendChart);
